import React, { createContext, useState, useContext, useEffect } from 'react';
import { authAPI } from '../utils/api';

const AuthContext = createContext();

export function useAuth() {
  return useContext(AuthContext);
}

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('token');
    const storedSalary = localStorage.getItem('salary');
    if (token) {
      // Mock user with optional salary
      setUser({ 
        name: 'Demo User', 
        email: 'demo@smartspend.com',
        salary: storedSalary ? parseFloat(storedSalary) : null
      });
      setLoading(false);
      
      // When backend is ready:
      // authAPI.verifyToken().then(userData => setUser(userData))
      //   .catch(() => localStorage.removeItem('token'))
      //   .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, []);

  const login = async (email, password) => {
    try {
      const mockUser = { 
        name: 'Demo User', 
        email,
        salary: localStorage.getItem('salary') ? parseFloat(localStorage.getItem('salary')) : null
      };
      const mockToken = 'mock-jwt-token';
      
      setUser(mockUser);
      localStorage.setItem('token', mockToken);
      return { user: mockUser, token: mockToken };
    } catch (error) {
      throw error;
    }
  };

  const register = async (userData) => {
    try {
      const mockUser = { 
        name: userData.name, 
        email: userData.email,
        salary: null // salary not set yet
      };
      const mockToken = 'mock-jwt-token';
      
      setUser(mockUser);
      localStorage.setItem('token', mockToken);
      return { user: mockUser, token: mockToken };
    } catch (error) {
      throw error;
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('token');
    localStorage.removeItem('salary');
  };

  // New: Set or update monthly salary
  const setSalary = (amount) => {
    setUser(prev => ({ ...prev, salary: amount }));
    localStorage.setItem('salary', amount);
  };

  const value = {
    user,
    login,
    register,
    logout,
    setSalary,   // make salary editable
    loading
  };

  return (
    <AuthContext.Provider value={value}>
      {!loading && children}
    </AuthContext.Provider>
  );
}

export { AuthContext };
